/* com.erns.coching.cochingtv.mapper.CochingtvDAO.load */

SELECT

FROM T_CH_TV AA			

	AND AA.TV_SEQ = #{tvSeq, jdbcType=INTEGER}

/* com.erns.coching.cochingtv.mapper.CochingtvDAO.getList */
SELECT ZZ.* FROM ( SELECT
FROM T_CH_TV AA
AND AA.DEL_YN = 'N'
ORDER BY RANDOM()
ORDER BY AA.SORT_ORD ASC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}
